export interface ExtractedData {
  page: number;
  data: Record<string, string | number | null>;
  status: 'success' | 'error' | 'pending';
  errorMessage?: string;
}

export interface ProcessingStats {
  total: number;
  processed: number;
  success: number;
  failed: number;
}

export enum PageSelection {
  ALL = 'ALL',
  ODD = 'ODD',
  EVEN = 'EVEN',
}

export interface ExtractionConfig {
  fields: string;
  pageSelection: PageSelection;
  startPage: number;
  endPage?: number;
}

// We access pdfjsLib from the global window object since we loaded it via CDN in index.html
// to avoid complex bundler worker configuration issues in this environment.
declare global {
  interface Window {
    pdfjsLib: any;
  }
}

export const loadPdf = async (file: File): Promise<any> => {
  const arrayBuffer = await file.arrayBuffer();
  const loadingTask = window.pdfjsLib.getDocument({ data: arrayBuffer });
  return loadingTask.promise;
};

export const renderPageToImage = async (pdfDoc: any, pageNumber: number, scale = 1.5): Promise<string> => {
  const page = await pdfDoc.getPage(pageNumber);
  const viewport = page.getViewport({ scale });

  const canvas = document.createElement('canvas');
  const context = canvas.getContext('2d');
  canvas.height = viewport.height;
  canvas.width = viewport.width;

  if (!context) throw new Error('Could not get canvas context');

  await page.render({
    canvasContext: context,
    viewport: viewport,
  }).promise;

  // Convert to base64 string (remove data:image/png;base64, prefix for API)
  const dataUrl = canvas.toDataURL('image/jpeg', 0.8);
  return dataUrl;
};

import { GoogleGenAI, Type } from "@google/genai";

const getAiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("API Key not found");
  return new GoogleGenAI({ apiKey });
};

export const extractDataFromImage = async (
  base64Image: string,
  fieldsDescription: string
): Promise<Record<string, any>> => {
  const ai = getAiClient();

  // Clean base64 string if it has prefix
  const cleanBase64 = base64Image.replace(/^data:image\/(png|jpeg|jpg);base64,/, '');

  const prompt = `
    Analyze this document page image. 
    Extract the following information: ${fieldsDescription}.

    If the document contains a list or table, try to aggregate the main details. 
    If a specific field is not found, return null for that field.

    Return the result strictly as a valid JSON object.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: cleanBase64
            }
          },
          {
            text: prompt
          }
        ]
      },
      config: {
        responseMimeType: 'application/json',
        // We use loose schema definition here or just prompt for JSON to allow flexibility 
        // since user defines fields dynamically.
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text);
  } catch (error) {
    console.error("Gemini Extraction Error:", error);
    throw error;
  }
};

import * as XLSX from 'xlsx';
import { ExtractedData } from '../types';

export const exportToExcel = (data: ExtractedData[], fileName: string = 'extracted_data.xlsx') => {
  // Flatten data for Excel
  const flatData = data
    .filter(item => item.status === 'success')
    .map(item => ({
      Page: item.page,
      ...item.data
    }));

  if (flatData.length === 0) {
    console.warn("No data to export");
    return;
  }

  const worksheet = XLSX.utils.json_to_sheet(flatData);
  const workbook = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(workbook, worksheet, "Extracted Data");

  XLSX.writeFile(workbook, fileName);
};

import React, { ChangeEvent } from 'react';
import { Upload, FileText, AlertCircle } from 'lucide-react';

interface FileUploaderProps {
  onFileSelect: (file: File) => void;
  selectedFile: File | null;
  disabled: boolean;
}

export const FileUploader: React.FC<FileUploaderProps> = ({ onFileSelect, selectedFile, disabled }) => {
  const handleFileChange = (e: ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      if (file.type === 'application/pdf') {
        onFileSelect(file);
      } else {
        alert('Please upload a valid PDF file.');
      }
    }
  };

  return (
    <div className="w-full">
      <label 
        className={`flex flex-col items-center justify-center w-full h-48 border-2 border-dashed rounded-xl cursor-pointer transition-colors
        ${disabled 
          ? 'bg-gray-100 border-gray-300 cursor-not-allowed' 
          : 'bg-white border-blue-300 hover:bg-blue-50 hover:border-blue-500'}`}
      >
        <div className="flex flex-col items-center justify-center pt-5 pb-6">
          {selectedFile ? (
            <>
              <FileText className="w-12 h-12 text-blue-500 mb-3" />
              <p className="mb-2 text-sm text-gray-700 font-medium">
                {selectedFile.name}
              </p>
              <p className="text-xs text-gray-500">
                {(selectedFile.size / 1024 / 1024).toFixed(2)} MB
              </p>
              <p className="text-xs text-blue-500 mt-2 hover:underline">Click to change file</p>
            </>
          ) : (
            <>
              <Upload className="w-10 h-10 text-gray-400 mb-3" />
              <p className="mb-2 text-sm text-gray-600">
                <span className="font-semibold">Click to upload PDF</span>
              </p>
              <p className="text-xs text-gray-500">PDF files only (Max 500 pages recommended)</p>
            </>
          )}
        </div>
        <input 
          type="file" 
          className="hidden" 
          accept="application/pdf"
          onChange={handleFileChange}
          disabled={disabled}
        />
      </label>
    </div>
  );
};

